import { Pool } from 'pg';
import { EventEmitter } from 'events';
import { logger } from '../../../utils/logger';
import { TwitchAPIService } from '../../twitch/api';
import { DownloadHandler } from './downloadHandler';
import { TaskProgress } from '../types';

export class TaskHandler extends EventEmitter {
  private twitchAPI: TwitchAPIService;

  constructor(
    private pool: Pool,
    private downloadHandler: DownloadHandler
  ) {
    super();
    this.twitchAPI = TwitchAPIService.getInstance();
  }

  async executeTask(taskId: number): Promise<void> {
    const client = await this.pool.connect();
    try {
      // Verify task exists and is active
      const taskResult = await client.query(`
        SELECT t.*, 
               array_agg(DISTINCT c.twitch_id) as channel_ids,
               array_agg(DISTINCT g.twitch_game_id) as game_ids
        FROM tasks t
        LEFT JOIN channels c ON c.id = ANY(t.channel_ids)
        LEFT JOIN games g ON g.id = ANY(t.game_ids)
        WHERE t.id = $1 AND t.is_active = true
        GROUP BY t.id
      `, [taskId]);

      if (taskResult.rows.length === 0) {
        throw new Error(`Task ${taskId} not found or is inactive`);
      }

      const task = taskResult.rows[0];
      let totalChannels = 0;
      let processedChannels = 0;
      let totalVods = 0;
      let processedVods = 0;

      // Process channels
      if (task.channel_ids?.length > 0) {
        totalChannels = task.channel_ids.length;

        for (const channelId of task.channel_ids) {
          try {
            await this.updateTaskProgress(client, taskId, {
              message: `Processing channel ${channelId}`,
              total: totalChannels,
              completed: processedChannels,
              percentage: (processedChannels / totalChannels) * 100
            });

            const vods = await this.twitchAPI.getChannelVODs(channelId.toString());
            logger.info(`Found ${vods.length} downloadable VODs for channel ${channelId}`);
            totalVods += vods.length;

            for (const vod of vods) {
              try {
                await this.queueVODDownload(client, vod.id, task.priority, taskId);
                processedVods++;

                await this.updateTaskProgress(client, taskId, {
                  message: `Added VOD ${vod.id} to queue`,
                  total: totalVods,
                  completed: processedVods,
                  percentage: (processedVods / totalVods) * 100
                });
              } catch (error) {
                logger.error(`Error queuing VOD ${vod.id}:`, error);
              }
            }

            processedChannels++;
          } catch (error) {
            logger.error(`Error processing channel ${channelId}:`, error);
          }
        }
      }

      // Process games
      if (task.game_ids?.length > 0) {
        // Similar process for games...
        // Implement game VOD discovery logic here
      }

      // Update task completion
      await this.updateTaskCompletion(client, taskId, 'completed', {
        total_vods: totalVods,
        processed_vods: processedVods
      });

      this.emit('task:complete', {
        taskId,
        totalVods,
        processedVods
      });

    } catch (error) {
      logger.error(`Error executing task ${taskId}:`, error);
      await this.updateTaskCompletion(client, taskId, 'failed', {
        error: error instanceof Error ? error.message : 'Unknown error'
      });
      this.emit('task:error', { taskId, error });
      throw error;
    } finally {
      client.release();
    }
  }

  private async updateTaskProgress(
    client: Pool,
    taskId: number,
    progress: TaskProgress
  ): Promise<void> {
    try {
      await client.query(`
        UPDATE task_monitoring
        SET status_message = $2,
            items_total = $3,
            items_completed = $4,
            progress_percentage = $5,
            last_check_at = NOW(),
            updated_at = NOW()
        WHERE task_id = $1
      `, [
        taskId,
        progress.message,
        progress.total,
        progress.completed,
        progress.percentage
      ]);

      this.emit('task:progress', { taskId, ...progress });
    } catch (error) {
      logger.error(`Error updating task progress for task ${taskId}:`, error);
    }
  }

  private async updateTaskCompletion(
    client: Pool,
    taskId: number,
    status: 'completed' | 'failed',
    details: Record<string, any>
  ): Promise<void> {
    try {
      await client.query('BEGIN');

      // Update task monitoring
      await client.query(`
        UPDATE task_monitoring
        SET status = $2,
            status_message = $3,
            progress_percentage = $4,
            updated_at = NOW()
        WHERE task_id = $1
      `, [
        taskId,
        status,
        status === 'completed' ? 'Task completed successfully' : 'Task failed',
        status === 'completed' ? 100 : 0
      ]);

      // Update task status
      await client.query(`
        UPDATE tasks
        SET status = $2,
            updated_at = NOW(),
            error_message = $3
        WHERE id = $1
      `, [
        taskId,
        status,
        status === 'failed' ? details.error : null
      ]);

      await client.query('COMMIT');
    } catch (error) {
      await client.query('ROLLBACK');
      logger.error(`Error updating task completion for task ${taskId}:`, error);
    }
  }

  private async queueVODDownload(
    client: Pool,
    vodId: string,
    priority: string,
    taskId: number
  ): Promise<void> {
    try {
      await client.query('BEGIN');

      // Check if VOD exists
      const vodExists = await client.query(`
        SELECT id 
        FROM vods 
        WHERE twitch_id = $1::bigint
      `, [vodId]);

      if (vodExists.rows.length === 0) {
        // Create new VOD entry
        await client.query(`
          INSERT INTO vods (
            twitch_id,
            task_id,
            download_status,
            download_priority,
            retry_count,
            max_retries,
            created_at,
            updated_at
          ) VALUES (
            $1::bigint,
            $2,
            'queued',
            $3,
            0,
            3,
            NOW(),
            NOW()
          )
        `, [vodId, taskId, priority]);
      } else {
        // Update existing VOD
        await client.query(`
          UPDATE vods 
          SET download_status = 'queued',
              task_id = $2,
              download_priority = $3,
              retry_count = 0,
              updated_at = NOW()
          WHERE twitch_id = $1::bigint
        `, [vodId, taskId, priority]);
      }

      await client.query('COMMIT');
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    }
  }
}

// Filepath: backend/src/services/downloadManager/queue/queueProcessor.ts

import { Pool } from 'pg';
import { EventEmitter } from 'events';
import { logger } from '../../../utils/logger';
import { ResourceMonitor } from '../utils/resourceMonitor';
import { DownloadHandler } from '../handlers/downloadHandler';
import { QueueStatus } from '../types';

export class QueueProcessor extends EventEmitter {
  private processingInterval: NodeJS.Timeout | null = null;
  private isProcessing: boolean = false;
  private isShuttingDown: boolean = false;

  constructor(
    private pool: Pool,
    private downloadHandler: DownloadHandler,
    private resourceMonitor: ResourceMonitor,
    private maxConcurrent: number
  ) {
    super();
  }

  async startProcessing(intervalSeconds: number = 30): Promise<void> {
    if (this.isShuttingDown) {
      throw new Error('Cannot start processing while shutdown is in progress');
    }

    logger.info(`Starting download queue processing with ${intervalSeconds} second interval`);

    // Initial resource check
    await this.resourceMonitor.getSystemResources();

    // Initial queue processing
    await this.processQueue();

    // Set up interval for continuous processing
    this.processingInterval = setInterval(() => {
      this.processQueue().catch(error => {
        logger.error('Error in download queue interval:', error);
      });
    }, intervalSeconds * 1000);
  }

  async stopProcessing(): Promise<void> {
    this.isShuttingDown = true;

    if (this.processingInterval) {
      clearInterval(this.processingInterval);
      this.processingInterval = null;
    }

    // Wait for current processing to complete
    if (this.isProcessing) {
      logger.info('Waiting for current queue processing to complete...');
      await new Promise<void>(resolve => {
        const checkInterval = setInterval(() => {
          if (!this.isProcessing) {
            clearInterval(checkInterval);
            resolve();
          }
        }, 1000);
      });
    }

    this.isShuttingDown = false;
    logger.info('Queue processing stopped');
  }

  private async processQueue(): Promise<void> {
    if (this.isShuttingDown || this.isProcessing) {
      return;
    }

    this.isProcessing = true;
    const client = await this.pool.connect();

    try {
      // Check system resources
      const resources = await this.resourceMonitor.getSystemResources();
      const activeDownloads = this.downloadHandler.getActiveDownloads();

      // Skip if resources are constrained
      if (
        resources.diskSpace.available < 10 * 1024 * 1024 * 1024 || // 10GB
        resources.memoryUsage.free / resources.memoryUsage.total < 0.1 // 10% free memory
      ) {
        logger.warn('Skipping queue processing due to resource constraints');
        return;
      }

      // Get next batch of VODs to process
      const result = await client.query(`
        SELECT v.*, t.priority as task_priority
        FROM vods v
        LEFT JOIN tasks t ON v.task_id = t.id
        WHERE v.download_status = 'queued'
        AND (v.retry_count IS NULL OR v.retry_count < v.max_retries)
        ORDER BY
          CASE v.download_priority
            WHEN 'critical' THEN 1
            WHEN 'high' THEN 2
            WHEN 'normal' THEN 3
            WHEN 'low' THEN 4
          END,
          v.scheduled_for ASC
        LIMIT $1
      `, [this.maxConcurrent - activeDownloads.size]);

      for (const vod of result.rows) {
        try {
          // Emit download start event
          this.emit('download:start', vod.id);

          // Start the download
          await this.downloadHandler.processVOD(vod);

          // Emit download complete event
          this.emit('download:complete', vod.id);
        } catch (error) {
          logger.error(`Error processing VOD ${vod.id}:`, error);
          this.emit('download:error', {
            vodId: vod.id,
            error: error instanceof Error ? error : new Error(String(error))
          });
        }
      }
    } catch (error) {
      logger.error('Error processing download queue:', error);
    } finally {
      this.isProcessing = false;
      client.release();
    }
  }

  async getQueueStatus(): Promise<QueueStatus> {
    const client = await this.pool.connect();
    try {
      const result = await client.query(`
        SELECT 
          COUNT(CASE WHEN download_status = 'queued' THEN 1 END) as pending,
          COUNT(CASE WHEN download_status = 'downloading' THEN 1 END) as downloading,
          COUNT(CASE WHEN download_status = 'failed' THEN 1 END) as failed,
          COUNT(CASE WHEN download_status = 'completed' THEN 1 END) as completed
        FROM vods
        WHERE download_status IN ('queued', 'downloading', 'failed', 'completed')
      `);

      return {
        pending: parseInt(result.rows[0].pending) || 0,
        downloading: parseInt(result.rows[0].downloading) || 0,
        failed: parseInt(result.rows[0].failed) || 0,
        completed: parseInt(result.rows[0].completed) || 0
      };
    } finally {
      client.release();
    }
  }
}

// Filepath: backend/src/services/downloadManager/utils/checksums.ts

import crypto from 'crypto';
import { createReadStream } from 'fs';
import { logger } from '../../../utils/logger';

export class Checksums {
  static async calculateMD5(filePath: string): Promise<string> {
    return new Promise((resolve, reject) => {
      const hash = crypto.createHash('md5');
      const stream = createReadStream(filePath);

      stream.on('data', (data) => hash.update(data));
      stream.on('end', () => resolve(hash.digest('hex')));
      stream.on('error', (error) => {
        logger.error(`Error calculating MD5 for file ${filePath}:`, error);
        reject(error);
      });
    });
  }

  static async verifyChecksum(filePath: string, expectedChecksum: string): Promise<boolean> {
    try {
      const actualChecksum = await this.calculateMD5(filePath);
      return actualChecksum === expectedChecksum;
    } catch (error) {
      logger.error(`Error verifying checksum for file ${filePath}:`, error);
      throw error;
    }
  }

  static async calculateFileHashes(filePath: string): Promise<{
    md5: string;
    sha256: string;
  }> {
    return new Promise((resolve, reject) => {
      const md5Hash = crypto.createHash('md5');
      const sha256Hash = crypto.createHash('sha256');
      const stream = createReadStream(filePath);

      stream.on('data', (data) => {
        md5Hash.update(data);
        sha256Hash.update(data);
      });

      stream.on('end', () => {
        resolve({
          md5: md5Hash.digest('hex'),
          sha256: sha256Hash.digest('hex')
        });
      });

      stream.on('error', (error) => {
        logger.error(`Error calculating hashes for file ${filePath}:`, error);
        reject(error);
      });
    });
  }

  static async verifyFileIntegrity(
    filePath: string,
    checksums: { md5?: string; sha256?: string }
  ): Promise<boolean> {
    try {
      const hashes = await this.calculateFileHashes(filePath);

      if (checksums.md5 && hashes.md5 !== checksums.md5) {
        logger.warn(`MD5 mismatch for file ${filePath}`);
        return false;
      }

      if (checksums.sha256 && hashes.sha256 !== checksums.sha256) {
        logger.warn(`SHA256 mismatch for file ${filePath}`);
        return false;
      }

      return true;
    } catch (error) {
      logger.error(`Error verifying file integrity for ${filePath}:`, error);
      throw error;
    }
  }
}

// Filepath: backend/src/services/downloadManager/utils/fileSystem.ts

import { promises as fs } from 'fs';
import path from 'path';
import os from 'os';
import { logger } from '../../../utils/logger';

export class FileSystemManager {
  constructor(private tempDir: string) {}

  async createTempDirectory(vodId: string): Promise<string> {
    const tempPath = path.join(this.tempDir, `vod-${vodId}`);
    await fs.mkdir(tempPath, { recursive: true });
    return tempPath;
  }

  async createDownloadDirectory(basePath: string, username: string, date: string, vodId: string): Promise<string> {
    const downloadPath = path.join(basePath, username, date, vodId);
    await fs.mkdir(downloadPath, { recursive: true });
    return downloadPath;
  }

  async writeMetadata(outputPath: string, metadata: any): Promise<void> {
    await fs.writeFile(
      path.join(outputPath, 'metadata.json'),
      JSON.stringify(metadata, null, 2),
      'utf-8'
    );
  }

  async cleanupDirectory(dirPath: string): Promise<void> {
    try {
      await fs.rm(dirPath, { recursive: true, force: true });
    } catch (error) {
      logger.error(`Error cleaning up directory ${dirPath}:`, error);
      throw error;
    }
  }

  async getDirectorySize(dirPath: string): Promise<number> {
    const files = await fs.readdir(dirPath);
    let size = 0;

    for (const file of files) {
      const filePath = path.join(dirPath, file);
      const stats = await fs.stat(filePath);
      if (stats.isDirectory()) {
        size += await this.getDirectorySize(filePath);
      } else {
        size += stats.size;
      }
    }

    return size;
  }

  async cleanupOldFiles(directory: string, maxAgeHours: number): Promise<void> {
    const files = await fs.readdir(directory);
    const now = Date.now();
    const maxAge = maxAgeHours * 60 * 60 * 1000;

    for (const file of files) {
      const filePath = path.join(directory, file);
      try {
        const stats = await fs.stat(filePath);
        const age = now - stats.mtimeMs;

        if (age > maxAge) {
          if (stats.isDirectory()) {
            await fs.rm(filePath, { recursive: true, force: true });
          } else {
            await fs.unlink(filePath);
          }
          logger.info(`Cleaned up old file: ${file}`);
        }
      } catch (error) {
        logger.error(`Error cleaning up file ${file}:`, error);
      }
    }
  }

  async ensureDirectoryExists(dirPath: string): Promise<void> {
    await fs.mkdir(dirPath, { recursive: true });
  }
}

